sql:
SELECT project_name, start_date, end_date, status, project_type_id, methodology
FROM projects
WHERE budget > (SELECT AVG(budget) FROM projects);

external_knowledge:
Well-funded projects: projects with budgets above the average budget;
A lot of completed work: more than 10 completed tasks; 
The time needed to finish a task: the estimated hours to complete a task.

sql:
SELECT DISTINCT task_name
FROM tasks
WHERE priority = 5 AND status <> 'Completed';

SELECT AVG(budget) AS average_budget, AVG(actual_cost) AS average_actual_cost
FROM projects
WHERE project_type_id = 1;

SELECT AVG(actual_cost) AS average_actual_cost
FROM projects
WHERE status = 'Active';

SELECT P.project_name, PM.method_name, P.status
FROM projects P
JOIN project_methods PM ON P.methodology = PM.method_name;

SELECT task_id, label_id
FROM task_label_assignments
WHERE label_id = 1;

SELECT file_path 
FROM project_documents 
WHERE project_id = 0 AND document_id = 0;

SELECT COUNT(*)
FROM project_integrations
WHERE integration_type = 'GitHub';
